public void ClearSignaledSchedulingChange()
    {
        lock (sigLock)
        {
            signaled = false;
            signaledNextFireTimeUtc = SchedulerConstants.SchedulingSignalDateTime;
        }

        // Drain any buffered permits so WaitAsync blocks cleanly on next call.
        // Prevents stale permits from causing unbounded spurious wakeups.
        while (schedulingChangeSignal.Wait(0)) { }
    }

public virtual ITrigger Clone()
    {
        AbstractTrigger copy = (AbstractTrigger) MemberwiseClone();

        // Shallow copy the jobDataMap.  Note that this means that if a user
        // modifies a value object in this map from the cloned Trigger
        // they will also be modifying this Trigger.
        if (jobDataMap is not null)
        {
            copy.jobDataMap = (JobDataMap) jobDataMap.Clone();
        }

        return copy;
    }

void Dispatch(LogEvent logEvent)
    {
        // The enricher may be a "safe" aggregate one, but is most commonly bare and so
        // the exception handling from SafeAggregateEnricher is duplicated here.
        try
        {
            _enricher.Enrich(logEvent, _messageTemplateProcessor);
        }
        catch (Exception ex)
        {
            SelfLog.WriteLine("Exception {0} caught while enriching {1} with {2}.", ex, logEvent, _enricher);
        }

        _sink.Emit(logEvent);
    }
